// ---- Understanding recomposition ----
@Composable
fun RecompositionExample() {
    var count by remember { mutableStateOf(0) }
    var text by remember { mutableStateOf("") }

    Column(
        modifier = Modifier.padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // This recomposes when count changes
        Text(
            text = "Count: $count",
            fontSize = 24.sp,
            modifier = Modifier
                .fillMaxWidth()
                .background(Color.LightGray)
                .padding(8.dp)
        )

        // This does NOT recompose when count changes (no state)
        Text(
            text = "This text doesn't recompose with count",
            color = Color.Gray
        )

        Row(
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = { count++ }) {
                Text("Increment")
            }
            Button(onClick = { count-- }) {
                Text("Decrement")
            }
        }

        OutlinedTextField(
            value = text,
            onValueChange = { text = it },
            label = { Text("Enter text") }
        )
    }
}

// ---- Skipping recomposition ----
@Composable
fun SkippingRecomposition() {
    var count by remember { mutableStateOf(0) }
    var other by remember { mutableStateOf(0) }

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        Text("Count: $count")
        Text("Other: $other")

        // This button only updates count
        Button(onClick = { count++ }) {
            Text("Update Count")
        }

        // This button only updates other
        Button(onClick = { other++ }) {
            Text("Update Other")
        }
    }
}

// ---- Lambda stability ----
@Composable
fun LambdaStability() {
    var count by remember { mutableStateOf(0) }

    // This lambda is recreated on every recomposition
    val onIncrement = { count++ }

    // Use remember to stabilize the lambda
    val onIncrementStable = remember {
        { count++ }
    }

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        Text("Count: $count")

        Button(onClick = onIncrementStable) {
            Text("Increment (stable)")
        }
    }
}

// ---- Derived state to reduce recomposition ----
@Composable
fun DerivedStateOptimization() {
    var text by remember { mutableStateOf("") }

    // This recomputes on every change
    val charCount = text.length

    // This only recomputes when the result changes
    val isValid = remember(text) {
        text.length >= 3
    }

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        OutlinedTextField(
            value = text,
            onValueChange = { text = it },
            label = { Text("Enter text (min 3 chars)") }
        )

        Text("Characters: $charCount")
        Text(
            text = if (isValid) "✅ Valid" else "❌ Too short",
            color = if (isValid) Color.Green else Color.Red
        )
    }
}

// ---- CompositionLocal for implicit state ----
@Composable
fun CompositionLocalExample() {
    // Using LocalConfiguration for configuration changes
    val configuration = LocalConfiguration.current
    val screenWidth = configuration.screenWidthDp

    Text(
        text = "Screen width: ${screenWidth}dp",
        modifier = Modifier.padding(16.dp)
    )
}

// ---- Side effects ----
@Composable
fun SideEffectExample() {
    var count by remember { mutableStateOf(0) }

    // LaunchedEffect runs on first composition
    LaunchedEffect(Unit) {
        // Runs once
        println("LaunchedEffect: Initial setup")
    }

    // SideEffect runs after recomposition
    SideEffect {
        println("SideEffect: Count is $count")
    }

    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        Text("Count: $count")
        Button(onClick = { count++ }) {
            Text("Increment")
        }
    }
}

