@Composable
fun OptimizedRecomposition() {
    var count by remember { mutableStateOf(0) }
    val isEven by remember { derivedStateOf { count % 2 == 0 } }

    // Expensive calculation with remember
    val expensiveResult = remember {
        expensiveCalculation()
    }

    // Stable lambda
    val onIncrement = remember { { count++ } }
    val onDecrement = remember { { count-- } }
    val onReset = remember { { count = 0 } }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = "Count: $count",
            fontSize = 32.sp,
            fontWeight = FontWeight.Bold
        )

        Text(
            text = if (isEven) "✅ Even" else "❌ Odd",
            color = if (isEven) Color.Green else Color.Red,
            fontSize = 20.sp
        )

        Text(
            text = "Expensive result: $expensiveResult",
            fontSize = 14.sp,
            color = Color.Gray
        )

        Row(
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = onDecrement) {
                Text("−")
            }
            Button(onClick = onIncrement) {
                Text("+")
            }
            Button(onClick = onReset) {
                Text("Reset")
            }
        }

        Spacer(modifier = Modifier.height(16.dp))

        // Items with keys
        val items = listOf("Item A", "Item B", "Item C")
        Column(
            verticalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            items.forEach { item ->
                Text(
                    text = item,
                    key = item,
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.LightGray)
                        .padding(8.dp)
                )
            }
        }
    }
}

// Simulate expensive calculation
fun expensiveCalculation(): Int {
    var result = 0
    for (i in 1..10_000_000) {
        result += i
    }
    return result % 100
}

